class Solution {
public:
    int getMinSwaps(string num, int k) {
        string target = num;
        for (int i = 0; i < k; ++i) {
            next_permutation(target.begin(), target.end());
        }
        return countSwaps(num, target);
    }

    int countSwaps(const string& num, const string& target) {
        int n = num.size();
        int res = 0;
        vector<int> pos(10, -1);
        for (int i = n - 1; i >= 0; --i) {
            int d = target[i] - '0';
            pos[d] = i;
        }
        for (int i = 0; i < n; ++i) {
            int d = num[i] - '0';
            res += abs(i - pos[d]);
            for (int j = d; j >= 0; --j) {
                --pos[j];
            }
        }
        return res;
    }

    bool next_permutation(string::iterator first, string::iterator last) {
        if (first == last) return false;
        string::iterator i = last;
        if (first == --i) return false;
        while (true) {
            string::iterator i1, i2;
            i1 = i;
            if (*--i < *i1) {
                i2 = last;
                while (!(*i < *--i2));
                iter_swap(i, i2);
                reverse(i1, last);
                return true;
            }
            if (i == first) {
                reverse(first, last);
                return false;
            }
        }
    }

    void iter_swap(string::iterator a, string::iterator b) {
        char tmp = *a;
        *a = *b;
        *b = tmp;
    }

    void reverse(string::iterator first, string::iterator last) {
        while ((first != last) && (first != --last)) {
            iter_swap(first++, last);
        }
    }
};
